import{_ as e,o as t,c as a,a3 as r}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"上下文压缩 (Context Compression)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/context-compression.md","filePath":"user-guide/tools/llm-chat/context-pipeline/context-compression.md","lastUpdated":1778239080000}'),n={name:"user-guide/tools/llm-chat/context-pipeline/context-compression.md"};function l(i,o,s,c,h,d){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="上下文压缩-context-compression" tabindex="-1">上下文压缩 (Context Compression) <a class="header-anchor" href="#上下文压缩-context-compression" aria-label="Permalink to &quot;上下文压缩 (Context Compression)&quot;">​</a></h1><p>上下文压缩是 LLM Chat 处理超长对话的核心技术。它通过将旧的消息历史“总结”为简洁的摘要，在节省大量 Token 的同时，确保 AI 依然能够记住对话的关键背景。</p><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>与传统的“截断”策略（直接丢弃旧消息）不同，压缩系统采取了<strong>非破坏性总结</strong>方案：</p><ol><li><strong>检测</strong>：系统监控当前对话的 Token 总数或消息条数。</li><li><strong>总结</strong>：当达到阈值时，系统选取最旧的一段消息，调用 AI 模型生成一份摘要。</li><li><strong>替换</strong>：创建一个特殊的“压缩节点”插入对话树，并将被总结的原始消息在发送给 AI 时隐藏。</li><li><strong>保留</strong>：原始消息依然保存在你的本地数据库中，你可以随时禁掉压缩节点来恢复它们。</li></ol><hr><h2 id="触发机制" tabindex="-1">触发机制 <a class="header-anchor" href="#触发机制" aria-label="Permalink to &quot;触发机制&quot;">​</a></h2><p>你可以在“智能体编辑器 -&gt; 参数设置 -&gt; 上下文压缩”中配置触发规则。</p><h3 id="_1-自动触发" tabindex="-1">1. 自动触发 <a class="header-anchor" href="#_1-自动触发" aria-label="Permalink to &quot;1. 自动触发&quot;">​</a></h3><p>开启 <strong>“自动触发压缩”</strong> 后，系统会在你发送消息前检查以下条件：</p><ul><li><strong>Token 阈值</strong>：当前上下文 Token 超过设定值（如 80,000）时触发。</li><li><strong>消息条数</strong>：对话路径上的消息超过设定值（如 50 条）时触发。</li><li><strong>最小历史要求</strong>：为了防止过早压缩，你可以设置“最小历史条数”（如至少 15 条才允许压缩）。</li></ul><h3 id="_2-手动触发" tabindex="-1">2. 手动触发 <a class="header-anchor" href="#_2-手动触发" aria-label="Permalink to &quot;2. 手动触发&quot;">​</a></h3><p>在对话区域的工具栏或上下文统计面板中，你可以手动执行“立即压缩”。这会忽略自动触发的阈值限制。</p><hr><h2 id="压缩策略" tabindex="-1">压缩策略 <a class="header-anchor" href="#压缩策略" aria-label="Permalink to &quot;压缩策略&quot;">​</a></h2><p>为了保证对话质量，压缩过程遵循以下参数：</p><ul><li><strong>保护最近消息 (<code>protectRecentCount</code>)</strong>：最近的 N 条消息（默认 10 条）永远不会被压缩。这能确保 AI 对当前正在讨论的话题保持最高清晰度的记忆。</li><li><strong>每次压缩条数 (<code>compressCount</code>)</strong>：触发时，系统一次性将最早的 N 条消息（默认 20 条）合并为一个摘要。</li><li><strong>摘要节点角色</strong>：你可以指定摘要以 <code>System</code>、<code>User</code> 或 <code>Assistant</code> 身份呈现。通常建议使用 <code>System</code> 以获得更好的权威性。</li></ul><hr><h2 id="摘要生成配置" tabindex="-1">摘要生成配置 <a class="header-anchor" href="#摘要生成配置" aria-label="Permalink to &quot;摘要生成配置&quot;">​</a></h2><p>摘要的质量直接决定了 AI 后的表现。</p><h3 id="模型选择" tabindex="-1">模型选择 <a class="header-anchor" href="#模型选择" aria-label="Permalink to &quot;模型选择&quot;">​</a></h3><ul><li><strong>默认</strong>：使用当前对话所选的模型。</li><li><strong>专用模型</strong>：你可以指定一个更便宜或更擅长总结的模型（如 GPT-4o-mini 或 Gemini Flash）专门负责生成摘要。</li></ul><h3 id="提示词模板" tabindex="-1">提示词模板 <a class="header-anchor" href="#提示词模板" aria-label="Permalink to &quot;提示词模板&quot;">​</a></h3><p>系统区分了两种压缩场景：</p><ol><li><strong>初始摘要 (<code>summaryPrompt</code>)</strong>：用于第一次对原始消息进行压缩。</li><li><strong>续写摘要 (<code>continueSummaryPrompt</code>)</strong>：当已有摘要节点且需要追加新消息时，系统会将“旧摘要 + 新消息”交给 AI，生成一份包含所有信息的“新总摘要”。</li></ol><hr><h2 id="交互与管理" tabindex="-1">交互与管理 <a class="header-anchor" href="#交互与管理" aria-label="Permalink to &quot;交互与管理&quot;">​</a></h2><h3 id="压缩节点-ui" tabindex="-1">压缩节点 UI <a class="header-anchor" href="#压缩节点-ui" aria-label="Permalink to &quot;压缩节点 UI&quot;">​</a></h3><p>压缩节点在消息列表中以特殊的样式显示：</p><ul><li><strong>统计信息</strong>：显示该摘要包含的原始消息条数。</li><li><strong>手动编辑</strong>：你可以点击“编辑”按钮，手动修改 AI 生成的摘要内容，修正关键信息的遗漏。</li><li><strong>开关控制</strong>：点击节点上的“数据库/压缩”图标，可以临时禁用该压缩。禁用后，系统在下次请求时会重新发送被隐藏的原始消息。</li></ul><h3 id="性能提示" tabindex="-1">性能提示 <a class="header-anchor" href="#性能提示" aria-label="Permalink to &quot;性能提示&quot;">​</a></h3><ul><li><strong>流式处理</strong>：如果启用了“流式处理”，摘要生成过程将是异步的，不会阻塞你的正常对话。</li><li><strong>非破坏性</strong>：压缩操作仅修改对话树的结构关系，不会删除任何历史数据。</li></ul><hr><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="./analyzer"><code>context-pipeline/analyzer.md</code></a></li><li><a href="./../sessions/tree-graph"><code>sessions/tree-graph.md</code></a></li></ul>',35)])])}const g=e(n,[["render",l]]);export{p as __pageData,g as default};
